#include <stdio.h>
int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &N) != 1) return 0;
        if (N == 15) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

